import React, { useMemo, useState, useEffect } from 'react';
import {
    MapContainer,
    TileLayer,
    Marker,
    Popup,
    Polyline,
    useMap
} from 'react-leaflet';

import L from 'leaflet';
import 'leaflet/dist/leaflet.css';

import { Box, Button, Typography } from '@mui/material';

// ================= FIX LEAFLET ICON =================
delete L.Icon.Default.prototype._getIconUrl;

L.Icon.Default.mergeOptions({
    iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
    iconUrl: require('leaflet/dist/images/marker-icon.png'),
    shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

// ================= CUSTOM MARKERS =================
const getMarkerIcon = (index, total) => {
    let color = 'blue';

    if (index === 0) color = 'green';
    else if (index === total - 1) color = 'red';

    return new L.Icon({
        iconUrl: `https://raw.githubusercontent.com/pointhi/leaflet-color-markers/master/img/marker-icon-${color}.png`,
        shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
        iconSize: [25, 41],
        iconAnchor: [12, 41]
    });
};

// ================= DISTANCE CALC =================
const getDistance = (lat1, lon1, lat2, lon2) => {
    const R = 6371;
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;

    const a =
        Math.sin(dLat / 2) ** 2 +
        Math.cos(lat1 * Math.PI / 180) *
        Math.cos(lat2 * Math.PI / 180) *
        Math.sin(dLon / 2) ** 2;

    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    return (R * c).toFixed(2);
};

// ================= AUTO FIT =================
const FitBounds = ({ path }) => {
    const map = useMap();

    useEffect(() => {
        if (path.length > 1) {
            map.fitBounds(path, { padding: [40, 40] });
        }
    }, [path, map]);

    return null;
};

const MapView = ({ punches = [] }) => {

    const [selectedIndex, setSelectedIndex] = useState(null);
    const [fullScreen, setFullScreen] = useState(false);

    // ================= CLEAN + SORT =================
    const displayPunches = useMemo(() => {

        const cleaned = punches
            .filter(p => p.latitude && p.longitude)
            .map(p => ({
                ...p,
                latitude: Number(p.latitude),
                longitude: Number(p.longitude)
            }))
            .sort((a, b) => new Date(a.punched_at) - new Date(b.punched_at));

        // 🔥 performance safe
        if (cleaned.length > 300) {
            return cleaned.slice(-300);
        }

        return cleaned;

    }, [punches]);

    // ================= RESET =================
    useEffect(() => {
        setSelectedIndex(null);
    }, [displayPunches]);

    // ================= PATH =================
    const path = useMemo(() => {
        return displayPunches.map(p => [p.latitude, p.longitude]);
    }, [displayPunches]);

    // ================= DISTANCE =================
    const selectedDistance = useMemo(() => {

        if (selectedIndex === null || selectedIndex === 0) return 0;

        const start = displayPunches[0];
        const end = displayPunches[selectedIndex];

        return getDistance(
            start.latitude,
            start.longitude,
            end.latitude,
            end.longitude
        );

    }, [selectedIndex, displayPunches]);

    const defaultCenter = [23.0225, 72.5714];

    const last = displayPunches.length
        ? displayPunches[displayPunches.length - 1]
        : { latitude: defaultCenter[0], longitude: defaultCenter[1] };

    return (
        <Box sx={{
            position: fullScreen ? 'fixed' : 'relative',
            top: fullScreen ? 0 : 'auto',
            left: fullScreen ? 0 : 'auto',
            width: fullScreen ? '100vw' : '100%',
            height: fullScreen ? '100vh' : 'auto',
            zIndex: fullScreen ? 1300 : 'auto',
            background: '#fff'
        }}>

            {/* HEADER */}
            <Box sx={{ display: 'flex', justifyContent: 'space-between', p: 1 }}>
                <Typography variant="body2">
                    Total Points: {displayPunches.length}
                </Typography>

                <Button
                    size="small"
                    onClick={() => setFullScreen(!fullScreen)}
                >
                    {fullScreen ? "Exit Full Screen" : "Full Screen"}
                </Button>
            </Box>

            {/* POINT NAVIGATION */}
            <Box sx={{
                display: 'flex',
                gap: 1,
                overflowX: 'auto',
                p: 1
            }}>
                {displayPunches.map((p, i) => (
                    <Button
                        key={p.id || i}
                        size="small"
                        variant={selectedIndex === i ? "contained" : "outlined"}
                        onClick={() => setSelectedIndex(i)}
                    >
                        {i + 1}
                    </Button>
                ))}
            </Box>

            {/* DISTANCE INFO */}
            {selectedIndex !== null && (
                <Typography sx={{ p: 1 }}>
                    Distance (Point 1 → {selectedIndex + 1}): {selectedDistance} km
                </Typography>
            )}

            {/* MAP */}
            <MapContainer
                center={[last.latitude, last.longitude]}
                zoom={13}
                style={{
                    height: fullScreen ? '90vh' : '400px',
                    width: '100%',
                    borderRadius: 8
                }}
            >
                <TileLayer
                    url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />

                {path.length > 1 && <FitBounds path={path} />}

                {/* ROUTE LINE */}
                <Polyline
                    positions={path}
                    color="red"
                    weight={4}
                />

                {/* MARKERS */}
                {displayPunches.map((p, i) => (
                    <Marker
                        key={p.id || i}
                        position={[p.latitude, p.longitude]}
                        icon={getMarkerIcon(i, displayPunches.length)}
                        eventHandlers={{
                            click: () => setSelectedIndex(i)
                        }}
                    >
                        <Popup>
                            <b>Point {i + 1}</b><br />
                            {new Date(p.punched_at).toLocaleString()}<br />
                            Distance: {p.distance_from_last || 0} km
                        </Popup>
                    </Marker>
                ))}

            </MapContainer>

        </Box>
    );
};

export default React.memo(MapView);